const now = new Date();
return {
  currentTime: now.toISOString(),
  formatted: now.toLocaleString(),
  timezone: Intl.DateTimeFormat().resolvedOptions().timeZone
};

const { operation, value1, value2 } = $input;

let result;
switch(operation) {
  case 'roi':
    result = ((value2 - value1) / value1) * 100;
    return { result: `${result.toFixed(2)}%`, calculation: 'ROI' };
  case 'conversion':
    result = (value1 / value2) * 100;
    return { result: `${result.toFixed(2)}%`, calculation: 'Conversion Rate' };
  case 'savings':
    result = value1 - value2;
    return { result: result.toFixed(2), calculation: 'Cost Savings' };
  default:
    return { error: 'Unknown calculation type' };
}

